mapper.select:
SELECT COUNT(*) FROM suggestion WHERE sugg_usage = 'Y'
AND sugg_answer = #{sugg_answer}
AND ( UPPER(sugg_title) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(sugg_writer) LIKE '%' || UPPER(#{keyword}) || '%' )

SELECT * FROM ( SELECT ROWNUM RN, S.* FROM ( SELECT sugg_no, sugg_title, sugg_content, sugg_writer, sugg_pw, sugg_answer, sugg_cdate, sugg_mdate, sugg_usage FROM suggestion WHERE sugg_usage = 'Y'
AND sugg_answer = #{search.sugg_answer}
AND ( UPPER(sugg_title) LIKE '%' || UPPER(#{search.keyword}) || '%' OR UPPER(sugg_writer) LIKE '%' || UPPER(#{search.keyword}) || '%' )
ORDER BY sugg_no asc ) S ) WHERE RN BETWEEN #{page.startRow} AND #{page.endRow}
